parameters.functionCode:
const geminiResp = items[0].json.candidates[0].content.parts[0].text;
const cleanJson = geminiResp.replace(/```json/g, '').replace(/```/g, '').trim();
let ideas = [];
try {
  ideas = JSON.parse(cleanJson).ideas;
} catch (e) {
  ideas = [{ title: 'Error generating ideas', target_keyword: '', rationale: e.message }];
}

const htmlList = ideas.map(idea => `<li><b>Title:</b> ${idea.title}<br><b>Keyword:</b> ${idea.target_keyword}<br><b>Rationale:</b> ${idea.rationale}</li>`).join('');
return [{ json: { html: `<h2>Weekly SEO Blog Ideas</h2><ul>${htmlList}</ul>` } }];
